import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.M-AdQQii.js";const c=JSON.parse('{"title":"1.8 仙境（wonderisland）","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 仙境是NA 自制的活动地图（长期存在），当你的装备评分超过7000 后，可以通过主城（玛瑞诺普）喷泉处传送门进去，也可以通过传送门家具进入。如图所示： 完成每日任务可以获得仙境币，完成一定","frontmatter":{"title":"1.8 仙境（wonderisland）","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 仙境是NA 自制的活动地图（长期存在），当你的装备评分超过7000 后，可以通过主城（玛瑞诺普）喷泉处传送门进去，也可以通过传送门家具进入。如图所示： 完成每日任务可以获得仙境币，完成一定","outline":"deep"},"headers":[],"relativePath":"life/1-8.md","filePath":"life/1-8.md","lastUpdated":null}'),g={name:"life/1-8.md"};function u(l,s,p,r,o,d){return i(),e("div",null,[...s[0]||(s[0]=[t('<h1 id="_1-8-仙境-wonderisland" tabindex="-1">1.8 仙境（wonderisland） <a id="s102-288cbb11"></a> <a class="header-anchor" href="#_1-8-仙境-wonderisland" aria-label="Permalink to &quot;1.8 仙境（wonderisland） &lt;a id=&quot;s102-288cbb11&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_1-8-1-什么是仙境" tabindex="-1">1.8.1 什么是仙境 <a id="s103-464e7bdb"></a> <a class="header-anchor" href="#_1-8-1-什么是仙境" aria-label="Permalink to &quot;1.8.1 什么是仙境 &lt;a id=&quot;s103-464e7bdb&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>仙境是NA 自制的活动地图（长期存在），当你的装备评分超过7000 后，可以通过主城（玛瑞诺普）喷泉处传送门进去，也可以通过传送门家具进入。如图所示：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1346.jpeg" alt="图示：1.8.1 什么是仙境" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1347.jpeg" alt="图示：1.8.1 什么是仙境" loading="lazy"></figure><h2 id="_1-8-2-仙境的收益" tabindex="-1">1.8.2 仙境的收益 <a id="s104-3660e853"></a> <a class="header-anchor" href="#_1-8-2-仙境的收益" aria-label="Permalink to &quot;1.8.2  仙境的收益 &lt;a id=&quot;s104-3660e853&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>完成每日任务可以获得仙境币，完成一定次数后可以达成成就。</p><p>成就会给一个宝箱，宝箱里含有成就对应天数的帕洛斯、荣耀之星和仙境币。</p><p>仙境币可以换取各种东西，如：外形、家具、buff 等。具体可以在图示位置自行</p><p>查看：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1355.jpeg" alt="图示：1.8.2 仙境的收益" loading="lazy"></figure><h2 id="_1-8-3-仙境门票任务" tabindex="-1">1.8.3 仙境门票任务 <a id="s105-7d7dbb7b"></a> <a class="header-anchor" href="#_1-8-3-仙境门票任务" aria-label="Permalink to &quot;1.8.3 仙境门票任务 &lt;a id=&quot;s105-7d7dbb7b&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>仙境任务并非每日刷新了就能做，你需要有门票才能做仙境任务，如果昨天的门票没过期可以不用接购票任务，购票任务在下图NPC 处接取：</p><p>然后去图片所在小亭子处购买门票</p><p>按F 交互后可以得到如下门票：</p><p>只要你手里有门票便可以做以下④个任务：</p><p>①仙境钓鱼②仙境挖矿③捕捉格罗亚④酒馆送货</p><p>各位置和完成流程如下：</p><p>①先到图示地图找到NPC 接取NPC</p><p>之前像正常钓小鱼一样装备上给的鱼竿开始钓任务道具就好，任务一旦提交鱼竿就会消失，但是你可以钓到鱼竿时间结束再交任务，这样子你就可以囤积很多任务道具，下次接到任务就可以直接提交。</p><p>②挖矿任务在门票广场附近的NPC 那接取，</p><p>可以在酒馆交货任务做完后再去酒馆后山做。只要是山就能挖矿。</p><p>任务要求挖矿10 个。</p><p>酒馆后山矿点如下图：</p><p>③抓格罗亚NPC 同样可以在门票任务广场附近找到</p><p>这个任务一般情况下在没有拿到红龙次数成就滑翔翼前无法完成（除非有英雄骑龙带你上去），因为这个空岛非常的高，没有无限爬升手段很难上去，虽然附近有空岛但是太远，没有天空帝王也很难飞过去。接取任务后会获得一个限时的抓捕道具（过期就放弃任务再重新接任务）。飞到岛上后，操作如下图：</p><p>抓到1 个格罗亚后，可以通过岛上的传送门回去交任务。如图：</p><p>④酒馆送货任务在下图位置NPC 处可以接到，由于仙境这个地图就算叫出来载具也是没有货框的，所以你只能一个个运货到NPC 那里，当然你可以骑毛驴来加快你的移动速度。送货任务要求你送5 个货。</p><p>货物所在位置如图：</p><p>以上4 个任务皆为每日任务，每个任务在完成15、30、60 次时分别可以完成一个成就。成就会送一个箱子，箱子里有帕洛斯、荣耀之星和仙境币，数量和你完成任务的次数对应。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1361.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1362.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1367.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1368.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1369.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1374.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1375.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1380.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1381.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1386.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1387.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1388.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1393.jpeg" alt="图示：1.8.3 仙境门票任务" loading="lazy"></figure><h2 id="_1-8-4-仙境购买任务-2阶段任务" tabindex="-1">1.8.4 仙境购买任务（2阶段任务） <a id="s106-1379705d"></a> <a class="header-anchor" href="#_1-8-4-仙境购买任务-2阶段任务" aria-label="Permalink to &quot;1.8.4 仙境购买任务（2阶段任务） &lt;a id=&quot;s106-1379705d&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>在仙境里面有些任务即便你拥有免费的门票还是不够的，你需要用仙境币去购买图示道具才能解锁这些任务。</p><p>15 个仙境币可以买7 天的书，右键书可以获得一个仅在仙境保留的BUFF。</p><p>有BUFF 才能开始做2 阶段任务，BUFF 加成内容为：移动速度+15% 游泳速度+15% 滑翔速度+15% 语言熟练度+10000。</p><p>2 阶段任务主要有以下2 个：</p><p>①找宝箱</p><p>②变动物找宝箱</p><p>这2 个任务同样拥有奖励帕洛斯、荣耀之星、仙境币的成就。</p><p>流程如下：</p><p>2 阶段任务过于麻烦，建议去熊猫群参考熊猫的仙境攻略。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1399.jpeg" alt="图示：1.8.4 仙境购买任务（2阶段任务）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1400.jpeg" alt="图示：1.8.4 仙境购买任务（2阶段任务）" loading="lazy"></figure>',56)])])}const m=a(g,[["render",u]]);export{c as __pageData,m as default};
